class Solution:
    def minimumLength(self, s):
        arr = list(s)
        changed = True
        while changed:
            changed = False
            n = len(arr)
            for i in range(n):
                c = arr[i]
                left = -1
                for j in range(i - 1, -1, -1):
                    if arr[j] == c:
                        left = j
                        break
                right = -1
                for j in range(i + 1, n):
                    if arr[j] == c:
                        right = j
                        break
                if left != -1 and right != -1:
                    del arr[right]
                    del arr[left]
                    changed = True
                    break
        return len(arr)

